import { normalizeRelativePath } from '@mintlify/common';
import { addWarning } from './warnings.js';
export const findInvalidSpecFile = (invalidSpecFiles, reference) => invalidSpecFiles?.find((file) => normalizeRelativePath(file.originalFileLocation) === normalizeRelativePath(reference));
export const warnInvalidSpecFiles = (invalidSpecFiles) => {
    for (const file of invalidSpecFiles ?? []) {
        addWarning({
            type: 'openapi',
            message: file.kind === 'syntax'
                ? `Error parsing ${file.originalFileLocation}: ${file.reason}`
                : `Error validating ${file.kind === 'asyncapi' ? 'AsyncAPI' : 'OpenAPI'} file ${file.originalFileLocation}: ${file.reason}`,
        });
    }
};
